+    input: &'a Value,
+    field: &str,
+) -> FcpResult<&'a serde_json::Map<String, Value>> {
+    input
+        .get(field)
+        .and_then(Value::as_object)
+        .ok_or(FcpError::InvalidRequest {
+            code: 1003,
+            message: format!("`{field}` must be a JSON object"),
+        })
+}
