+                        .filter_map(|field| field.as_str())
+                        .collect::<Vec<_>>()
+                        .join(" + ")
+                })
+                .collect::<Vec<_>>()
+                .join(" or ");
+            return Err(FcpError::InvalidRequest {
+                code: 1003,
+                message: format!(
+                    "Missing one required field set for {}: {groups}",
+                    operation_info.id.as_str()
+                ),
+            });
+        }
+    }
